int getMoneyAmount(int n) {
    int** dp = malloc((n+2)*sizeof(int*));
    for (int i=0;i<=n+1;i++){dp[i]=calloc(n+2,sizeof(int));}
    for (int len=2; len<=n; len++)
        for (int l=1; l+len-1<=n; l++) {
            int r=l+len-1; dp[l][r]=INT_MAX;
            for (int k=l;k<=r;k++){
                int c=k; int L=dp[l][k-1], R=dp[k+1][r];
                c += L>R?L:R;
                if(c<dp[l][r]) dp[l][r]=c;
            }
        }
    int ans=dp[1][n];
    for(int i=0;i<=n+1;i++) free(dp[i]); free(dp); return ans;
}
